// // This module selects between two 32-bit inputs based on the ALUSrc signal. When ALUSrc is 0, dataout equals datain; otherwise, it equals num.
module top_module(ALUSrc,datain,num,dataout);input ALUSrc;
input [31:0] datain;
input [31:0] num;
output [31:0] dataout;

assign dataout = (ALUSrc == 0) ? datain : num;

endmodule
